mapper.update:
UPDATE dm_messages
SET status = #{status},
    recalled_at = #{recalledAt},
    updated_at = #{recalledAt}
WHERE id = #{messageId}

UPDATE dm_conversations
SET last_message_id = #{lastMessageId},
    last_message_at = #{lastMessageAt},
    updated_at = #{lastMessageAt}
WHERE id = #{conversationId}

UPDATE dm_conversation_participants
SET unread_count = unread_count + 1,
    updated_at = CURRENT_TIMESTAMP
WHERE conversation_id = #{conversationId}
  AND user_id <> #{senderUserId}
  AND deleted_at IS NULL

UPDATE dm_conversation_participants p
JOIN dm_conversations c
  ON c.id = p.conversation_id
SET p.unread_count = 0,
    p.last_read_message_id = #{lastReadMessageId},
    p.last_read_at = #{lastReadAt},
    p.updated_at = #{lastReadAt}
WHERE p.user_id = #{userId}
  AND p.deleted_at IS NULL
  AND c.conversation_code = #{conversationCode}
